import React, { useState } from "react";
import { Camera } from "lucide-react";

export default function PatientRegistration() {
  const [photo, setPhoto] = useState(null);

  const handlePhotoUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setPhoto(URL.createObjectURL(file));
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 p-6">
      {/* Header */}
      <div className="flex justify-between items-start mb-6">
        <div>
          <h1 className="text-2xl font-semibold text-slate-800">Patient Registration</h1>
          <p className="text-sm text-slate-500 mt-1">HL7 v2.5 • ADT A04</p>
        </div>

        {/* Passport Photo Upload */}
        <div className="relative w-32 h-40 bg-white rounded-xl shadow-md border flex items-center justify-center overflow-hidden">
          {photo ? (
            <img
              src={photo}
              alt="patient"
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="text-center text-slate-400">
              <Camera className="mx-auto mb-2" />
              <p className="text-xs">Upload Photo</p>
            </div>
          )}
          <input
            type="file"
            accept="image/*"
            onChange={handlePhotoUpload}
            className="absolute inset-0 opacity-0 cursor-pointer"
          />
        </div>
      </div>

      {/* Form Card */}
      <div className="bg-white rounded-2xl shadow-lg p-8 space-y-10">
        {/* Patient Information */}
        <section>
          <h2 className="text-lg font-semibold text-slate-700 mb-4">Patient Information</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Input label="MRN" />
            <Input label="First Name" />
            <Input label="Last Name" />
            <Input label="Display Name" />
            <Input label="Date of Birth" type="date" />
            <Input label="Age" />
            <Select label="Gender" options={["Male", "Female", "Other"]} />
            <Select label="Marital Status" options={["Single", "Married"]} />
          </div>
        </section>

        {/* Contact Details */}
        <section>
          <h2 className="text-lg font-semibold text-slate-700 mb-4">Contact Details</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Input label="Address" />
            <Select label="Country" options={["India"]} />
            <Select label="City" options={["Bangalore", "Delhi", "Mumbai"]} />
            <Input label="Mobile Number" />
            <Input label="National ID Number" />
          </div>
        </section>

        {/* Identification */}
        <section>
          <h2 className="text-lg font-semibold text-slate-700 mb-4">Patient Identification</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 items-end">
            <Select label="ID Type" options={["Aadhaar Card", "Passport"]} />
            <Input label="ID Number" />
            <Input label="Expiry Date" type="date" />
            <button className="h-11 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700">
              Scan / Upload
            </button>
          </div>
        </section>

        {/* Emergency Contact */}
        <section>
          <h2 className="text-lg font-semibold text-slate-700 mb-4">Emergency Contact</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Input label="First Name" />
            <Input label="Last Name" />
            <Select label="Relationship" options={["Father", "Mother", "Spouse"]} />
            <Input label="Mobile Number" />
            <Select label="ID Type" options={["Aadhaar", "Passport"]} />
            <Input label="ID Number" />
            <Input label="Expiry Date" type="date" />
          </div>
        </section>

        {/* Submit */}
        <div className="flex justify-end">
          <button className="px-8 py-3 rounded-xl bg-blue-600 text-white font-semibold hover:bg-blue-700 shadow">
            Register Patient
          </button>
        </div>
      </div>
    </div>
  );
}

function Input({ label, type = "text" }) {
  return (
    <div>
      <label className="block text-sm font-medium text-slate-600 mb-1">{label}</label>
      <input
        type={type}
        className="w-full h-11 px-3 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
      />
    </div>
  );
}

function Select({ label, options }) {
  return (
    <div>
      <label className="block text-sm font-medium text-slate-600 mb-1">{label}</label>
      <select className="w-full h-11 px-3 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500">
        {options.map((op) => (
          <option key={op}>{op}</option>
        ))}
      </select>
    </div>
  );
}
